+// Reject degenerate reductions that only combine the carried value with the
+// operation's identity element (e.g., add with 0, mul with 1). Treating such
+// patterns as horizontal reductions (e.g., summing lanes) changes semantics.
+auto IsIdentityForOpcode = [](unsigned Opcode, const Constant *C) -> bool {
+  if (!C || isa<UndefValue>(C))
+    return false;
+  if (const auto *CI = dyn_cast<ConstantInt>(C)) {
+    switch (Opcode) {
+    case Instruction::Add:
+    case Instruction::Sub:
+      return CI->isZero();           // identity 0
+    case Instruction::Mul:
+      return CI->isOne();            // identity 1
+    case Instruction::And:
+      return CI->isMinusOne();       // identity all-ones
+    case Instruction::Or:
+    case Instruction::Xor:
+      return CI->isZero();           // identity 0
+    default:
+      break;
+    }
+  } else if (const auto *CFP = dyn_cast<ConstantFP>(C)) {
+    switch (Opcode) {
+    case Instruction::FAdd:
+    case Instruction::FSub:
+      return CFP->isZero();          // +0.0/-0.0
+    case Instruction::FMul:
+      return CFP->isExactlyValue(1.0);
+    default:
+      break;
+    }
+  }
+  return false;
+};
